        onSearch={onSearch}
        onChange={setUserId}
        notFoundContent={searching ? <Spin size="small" /> : null}
        options={options.map((u) => ({
          value: u.id,
          label: u.display_name ? `${u.display_name} · ${u.email}` : u.email,
        }))}
        style={{ flex: 1 }}
      />
      <Select
        value={permission}
        options={PERMISSION_OPTIONS}
